import modal
import os

app = modal.App("text-index-pipeline")

volume = modal.Volume.from_name("text-index-volume", environment_name="modal-vsdatagen")


@app.function(volumes={"/data": volume})
def index_documents(documents: list[str]) -> int:
    index_dir = "/data/index"
    os.makedirs(index_dir, exist_ok=True)

    for i, doc in enumerate(documents):
        path = f"{index_dir}/doc_{i}.txt"
        with open(path, "w") as f:
            f.write(doc)

    volume.commit()

    return len(documents)


@app.local_entrypoint()
def main():
    sample_documents = [
        "The quick brown fox jumps over the lazy dog.",
        "Modal is a cloud platform for running serverless Python functions.",
        "Text indexing enables fast full-text search across large document collections.",
    ]

    count = index_documents.remote(sample_documents)

    modal.Dict.from_name("text-index-output", create_if_missing=True).put(
        "doc_count", count
    )

    print(f"Indexed {count} documents.")
